(function(w){"use strict";const ID="fraction";function p(v){const s=String(v??"").replace(/,/g,"").trim();if(!/^[+-]?\d+$/.test(s))return null;try{return BigInt(s)}catch(_){return null}}function abs(n){return n<0n?-n:n}function gcd(a,b){a=abs(a);b=abs(b);while(b){const t=a%b;a=b;b=t}return a||1n}function norm(n,d){if(d<0n){n=-n;d=-d}const g=gcd(n,d);return[n/g,d/g]}function compute(x){let a=p(x.n1),b=p(x.d1),c=p(x.n2),d=p(x.d2);if([a,b,c,d].some(v=>v===null))return{error:"분자와 분모에 정수를 입력해 주세요."};if(b===0n||d===0n)return{error:"분모는 0이 될 수 없습니다."};let n,den;switch(x.op||"add"){case"add":n=a*d+c*b;den=b*d;break;case"sub":n=a*d-c*b;den=b*d;break;case"mul":n=a*c;den=b*d;break;case"div":if(c===0n)return{error:"0으로 나눌 수 없습니다."};n=a*d;den=b*c;break;default:return{error:"연산을 확인해 주세요."}}[n,den]=norm(n,den);const num=Number(n),dd=Number(den);return{numerator:n.toString(),denominator:den.toString(),fraction:n.toString()+"/"+den.toString(),decimal:Number.isFinite(num/dd)?num/dd:null}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>첫 번째 분수</label><div class="hm-calc-grid-2"><input class="hm-calc-input" data-n1 inputmode="numeric" placeholder="분자"><input class="hm-calc-input" data-d1 inputmode="numeric" placeholder="분모"></div></div><div class="hm-calc-field"><label>두 번째 분수</label><div class="hm-calc-grid-2"><input class="hm-calc-input" data-n2 inputmode="numeric" placeholder="분자"><input class="hm-calc-input" data-d2 inputmode="numeric" placeholder="분모"></div></div></div><div class="hm-calc-field"><label for="hm-fraction-op">연산</label><select id="hm-fraction-op" class="hm-calc-select"><option value="add">더하기 (+)</option><option value="sub">빼기 (-)</option><option value="mul">곱하기 (×)</option><option value="div">나누기 (÷)</option></select></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">분수 계산</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const q=s=>root.querySelector(s),n1=q("[data-n1]"),d1=q("[data-d1]"),n2=q("[data-n2]"),d2=q("[data-d2]"),op=q("select"),[go,reset]=root.querySelectorAll("button"),msg=q(".hm-calc-message"),res=q(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({n1:n1.value,d1:d1.value,n2:n2.value,d2:d2.value,op:op.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");const detail=r.decimal===null?"":`<dl><dt>소수값</dt><dd>${api.formatNumber(r.decimal,10)}</dd></dl>`;api.setResult(res,api.resultCard("기약분수",api.escapeHTML(r.fraction),detail));});reset.addEventListener("click",()=>{[n1,d1,n2,d2].forEach(v=>v.value="");op.value="add";api.setMessage(msg,"");api.clearResult(res);n1.focus();});}w.HM_CALC.register(ID,{compute,render});})(window);
